INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '255.240。则该主机的主机号是(13)；可以直接接收该主机 广播 信息的地址 范围 是 (14)。', "["[['A. 0.0.0.8", "B. 0.0.0.120", "C. 0.0.0.15", "D. 0.0.0.240']]"]", '', '', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '255.240。则该主机的主机号是(13)；可以直接接收该主机广播信息的地址范围是 (14)。', "["[['A. 192.55.12.120?192.55.12.127", "B. 192.55.12.112?192.55.12.127", "C. 192.55.12.1?192.55.12.254", "D. 192.55.12.0?192.55.12.255']]"]", 'B', '本题考查IP地址的基本知识。 IP地址由网络地址和主机地址两部分构成，主机地址可进一步划分为子网号和主机号两 部分，三者的区分需借助子网掩码实现。. 主机号是IP地址中去掉网络地址、子网号后的部分，其计算方法可简单利用公式“主机 号=IP地址AND(NOT(子网掩码))” 计算。 一台计算机发出的广播消息，只有处在同一子网(网络)内的计算机才能接收到。', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '255.240)=192.55.12.112，IP地址的最后4位为主机号，范围为0?15，加在子 网号后面即可。', "["[['A.  ICMP，回送请求报文", "B.  UDP，17类型报文", "C.  TCP，SYN报文", "D. PING，测试报文']]"]", '', '', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'H.X.Y/16的模式分配，其中H为分支机构的序号(0表示公司总部，分支机构总数不会超过 200)。 对该工程师确定的逻辑设计内容的评价，恰当的是(27) 。 每个分支机构能连网的计算机的数量最多为(28)，配置 IP地址 时掩码是(29)。', "["[['A. 内容全面，符合逻辑设计的工作准则", "B. 应去掉物理层技术选择这一部分", "C. 应去掉路由协议选择这一部分", "D. 应增加网络安全设计这一部分']]"]", 'D', '本题考查逻辑网络设计的相关知识。 逻辑网络设计应完成的主要设计包括网络结构的设计、物理层技术选择、局域网技术选 择与应用、广域网技术选择与应用、地址设计和命名模型、路由选择协议、网络管理方 案设计和网络安全方案设计。 采用10.H.X.Y/16的地址模式，每个机构可以用16位作为机构内的主机地址(去掉全0、 全1的地址)。 第28题：甲公司承接了乙公司的网络建设工作。由于待建网络规模很大，为确保建设工作顺 利进行，负责该项目的工程师在进行逻辑设计时提出了如下工作思路： ①明确逻辑设计工作的内容是：网络拓扑结构设计；物理层技术选择；局域网技术选择；广 域网技术选择；地址设计；路由协议选择；网络管理模式与工具选择；撰写逻辑设计文档。', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'H.X.Y/16的模式分配，其中H为分支机构的序号(0表示公司总部，分支机构总数不会超过 200)。 对该工程师确定的逻辑设计内容的评价，恰当的是(27) 。 每个分支机构能连网的计算机的数量最多为(28)，配置IP地址时掩码是(29)。', "["[['A. 16", "B. 256", "C. 65534", "D. 65536']]"]", 'C', '本题考查逻辑网络设计的相关知识。 逻辑网络设计应完成的主要设计包括网络结构的设计、物理层技术选择、局域网技术选 择与应用、广域网技术选择与应用、地址设计和命名模型、路由选择协议、网络管理方 案设计和网络安全方案设计。 采用10.n.X.Y/16的地址模式，每个机构可以用16位作为机构内的主机地址(去掉全0、 全1的地址)。 第29题：甲公司承接了乙公司的网络建设工作。由于待建网络规模很大，为确保建设工作顺 利进行，负责该项目的工程师在进行逻辑设计时提出了如下工作思路： ①明确逻辑设计工作的内容是：网络拓扑结构设计；物理层技术选择；局域网技术选择；广 域网技术选择；地址设计；路由协议选择；网络管理模式与工具选择；撰写逻辑设计文档。 ②在进行地址设计时，确定的方案是：按乙公司各分支机构的地理位置划分地址块，并按', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'H.X.Y/16的模式分配，其中H为分支机构的序号(0表示公司总部，分支机构总数不会超过 200)。 对该工程师确定的逻辑设计内容的评价，恰当的是(27) 。 每个分支机构能连网的计算机的数量最多为(28)，配置IP地址时掩码是(29)。', "["[['A. 255.0.0.0", "B. 255.255.0.0", "C. 255.255.255.0", "D. 255.255.240.0']]"]", 'B', '本题考查逻辑网络设计的相关知识。 逻辑网络设计应完成的主要设计包括网络结构的设计、物理层技术选择、局域网技术选', 2, '2009年综合知识', '2009,综合知识', 2009);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '75MB/S*2312/2346≈18.5MB/s。 第8题：对无线局域网，可显著提高数据率的技术是(7)，对有2台计算机、1个AP、采用 300Mbps的802.11n的WLAN，2台计算机数据传输的概率相同，则每台计算机实际传送用 户数据的最大理论速度最接近(8)MB/S。', "["[['A. 1.4", "B. 6.7", "C. 9.3", "D. 18.7']]"]", 'D', '本题无线局域网(WLAN)的基本知识。 WLAN采用CSMA/CA访问控制方式，多台计算机竞争使用一个信道与AP通信以发送数 据，计算机越多，冲突的机会越多，每台计算机实际获得的发送数据的机会越少，这种 方式限制了一个AP可服务的计算机的数量即网络的规模。 MIMO方式利用多个天线，分别使用不同的信道(频率)，可同时传输更多的信号，使得 一台计算机与AP之间的数据率显著提高，也允许更多的计算机同时传输数据。 对于2台计算机、1个AP的情况，因发送概率相同，则每台机计算获得的实际数据率可 认为是总带宽的一半即150Mbps，换算成以字节为单位的数据率18.75MB/S。 此题可进一步精确：WLAN帧最大长度为2346B，其中数据部分最大长度为2312B，所 以每台计算机实际发送用户数据的最大理论速度的近似值可表示为', 2, '2010年综合知识', '2010,综合知识', 2010);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '75MB/S*2312/2346≈18.5MB/s。 第9题：阻塞包 算法 (反馈抑制法)是一类典型的基于闭环控制原理的 拥塞控制 方法，其主要缺 点之一是(9)。', "["[['A. 显著降低通信效率", "B. 可能导致不公平", "C. 不能真正控制拥塞", "D. 降低网络可用性']]"]", 'B', '', 2, '2010年综合知识', '2010,综合知识', 2010);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '1.10的 数据 分组，将被转发到的位置是(14)。', "["[['A. 2", "B. 2", "C. 2", "D. 2']]"]", '', '', 2, '2010年综合知识', '2010,综合知识', 2010);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '1.10的数据分组，将被转发到的位置是(14)。', "["[['A. 甲机构的网络", "B. 乙机构的网络", "C. 不确定", "D. 甲、乙之外的一个网络']]"]", 'A', '本题考查IP地址，特别是CIDR地址格式的基本知识。 CIDR(Classless Inter-Domain Routing)将IP地址看成两级结构，用“IP首地址/网络 前缀位数”的形式表示。在一个网络内表示主机的地址位数为32-网络前缀位数。全0和 全1的地址不能作为普通地址分配。 对于CIDR格式的IP地址，在进行路由选择时遵循的原则是最长匹配，即选择路由表中 网络前缀部分与分组中IP地址前缀部分的相同部分最长的那个地址作为转发地址。 第15题： IPv6 地址分为3级，其中第1级表示的含义是(15)。', 2, '2010年综合知识', '2010,综合知识', 2010);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '总结 一个标准的C类网络有8位(8bit)主机ID，—个最小的子网至少需要4个地址(主机ID全0 和全1的地址不能用于分配，剩余两个为主机号)，因此，一个标准的C类网络最多可划 分2 ÷4=64个子网。 第11题：一个IP 数据包 经过一台 路由器 转发到另一个 网络 ，该IP 数据包 的头部字段中一定会 发生变化的是(11)。', "["[['A. 源 IP", "B. 协议号", "C. 目的 IP", "D. TTL']]"]", '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'TTL字段的作用 TTL是Time To Live的缩写，含义为“生存时间”。为避免因错误选路而产生的环路现 象(IP包在一个循环的路由中传递，永远到达不了目的地)。该字段定义了IP数据包可存 在的最大期限。由于确切的生存时间很难把握，该字段通常用跳跃站点数来度量，即当 数据包从一个网络传送到另一个网络时(即经过一个路由器的转发)，该字段的值减 1。当该字段为0时，数据包将被丢弃。 第12题：假定在一个 IPv4 网络 中只有两个主机HA和HB，HA和HB在同一个LAN内，并且没 有划分VLAN。如果HA和HB需要直接 通信 则需满足(12)。', "["[['A.  HA和HB必须在同一子网内", "B.  HA和HB必须在不同子网内", "C.  HA和HB无论在一个子网或不在一个子网都可以", "D.  HA和HB必须使用相同的操作系统']]"]", 'A', '本题考查LAN、VLAN的概念、IP子网与物理网络的映射关系以及IP选路原理。 LAN是物理上的一个广播域，在LAN的所有设备都能收到其他设备的广播信息。 VLAN是逻辑上的广播域，可以把一个LAN划分为多个VLAN。划分VLAN后，LAN内的 设备以VLAN为单位组成广播域。 在IPv4网络中，一个IP子网只能映射一个LAN或VLAN;多个IPv4子网，可以映射到一个 LAN或VLAN中。 同一子网内主机可直接通信；不同子网之间，主机必须通过路由器才能进行通信。 第13题：假定一个 IPv4 网络 由4段不同的LAN互联而成，每段LAN上的最大MTU值分别是 512、1024、2048和4096，则在这个 IPv4 网络 上可能出现 IPv4 分组(IP Packet)的最大长度 是(13)。', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '结论 一个稳定的RIP网络即为网络拓扑结构不再变化，路由表稳定，此时RIP分组30s广播一 次，路由老化周期为180s。如果每30分钟丢失一次路由器广播UDP报文，则不会对路 由器和网络产生任何影响。 第15题：在一个 子网 中有一个主机HA和 路由器 RX，HB是其他 子网 的主机。在主机HA中到 HB的路由是RX(HA经RX到达HB)。假定在HA和RX的 子网 中再增加一个 路由器 RY，想让HA 经RY到达HB，此时需要(15).', "["[['A.  RY发送路由重定向ICMP报文给HA", "B.  RX发送路由重定向ICMP报文给HA", "C.  RY发送路由重定向ICMP报文给HB", "D.  RX发送路由重定向ICMP报文给HB']]"]", 'B', '本题重点考查ICMP协议中路由重定向的概念。 Internet网络中的设备可分为路由器和主机两种，在路由器和主机中都需要具有正确的 路由表网络才能正常的工作。 在Internet中，路由信息的传输分为两种：一种是路由器和主机之间的路由信息传递， 它是由ICMP的路由功能完成的；另一种是路由器和路由器之间路由信息的交换，它们 要依靠特殊的协议来完成，这些特殊的协议就是路由协议。无论ICMP协议还是路由协 议，最终要在各自的结点上(包括主机和路由器)维护一个正确的路由表，以路由表决定 如何发送(针对主机)和转发(针对路由器)IP分组。 ICMP的路由功能包括两个功能：一是发现本地路由器；二是路由重定向。下图显示了 ICMP报文的路由器广告报文格式(类型=9)。 路由器广告报文包含路由器地址列表以及优先级选择级别。ICMP报文给出了类型值为 9，代码字段为空，表中地址总数和每个表项的大小以及路由器声明的“有效时间”。', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '半打开连接和半关闭连接的概念 TCP连接经三次握手建立后，如果一方已经关闭或异常终止连接而另一方却还不知道， 我们称这样的TCP连接为半打开(half-open)连接。任何一端的主机异常都可能导致发生 这种情况。只要不打算在半打开连接上传输数据，仍处于连接状态的一方就不会检测另 一方已经出现异常。TCP的Keepalive定时器用于发现并结束半打开连接。 TCP连接建立后，TCP提供了双向的数据通路。TCP提供了其中一端结束它的发送后还 能接收来自另一端数据的能力，这称为半关闭。半关闭是TCP连接关闭过程中完成了前 半部分的状态，这时只关闭了一个方向上的数据通道，另一个方向上仍然能够继续数据 传输。 第18题： IPv6 与 IPv4 相比，下列叙述正确的是(18)。', "["[['A.  IPv6地址也分为A、B、C、D、E 五类", "B. IPv6网络可直接使用IPv4的路由协议", "C. IPv6不能实现地址自动配置", "D. IPv6分组的头中增加了流标签(Flow Label)字段']]"]", 'D', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', 'IMAP4协议 IMAP revl(RFC2060)是Internet Message Access Protocol的缩写，是通过Internet 获取信息的一种协议。IMAP4是IMAP协议的第4个版本，正如POP3是POP协议的第3 个版本一样。IMAP是一种强有力的邮箱访问方式。 POP3提供了快捷的邮件下载服务，用户可以利用POP3把邮箱里的信下载到PC上进行 离线阅读。一旦邮件进入PC的本地硬盘，就可以选择把邮件从服务器上删除，然后脱 离与Internet的连接并选择在任何时候阅读已经下载的邮件。 IMAP支持用户在线阅读功能，支持Web Mail功能(不下载到本地，所有邮件都在邮件 服务器上)，允许用户在服务器上建立任意层次结构的文件夹，并且可以灵活地在文件 夹之间移动邮件，随心所欲地组织你的邮箱。当然，IMAP也支持邮件下载到本地阅读 (等同POP3功能) 第21题：在 互联网 上，当我们访问一个设备时，(21)。', "["[['A. 必须要有域名，才能访问", "B. 有IP地址就可以访问", "C. 必须同时有IP地址和域名", "D. 必须要有域名服务器']]"]", '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '结论 一个稳定的OSPF单区域网络，网络的拓扑结构稳定，即LSDB中的链路不发生变化，此 时所有的路由器中的LSDB都相同。 第23题：下列对 FTP 业务的描述正确的是(23)。', "["[['A.  FTP服务必须通过用户名和口令才能访问。FTP可以基于UDP或TCP传输信息", "B.  FTP服务器必须通过用户名和口令才能访问。FTP只能基于TCP传输信息", "C.  FTP服务器无须用户名和口令即可访问。FTP可以基于UDP或TCP传输信息", "D.  FTP服务器无须用户名和口令即可访问。FTP只能基于UDP传输信息']]"]", 'B', '本题考查对数据业务的理解和对FTP业务的访问机制的理解。 FTP业务属于文件传输类的数据业务。针对Internet网络而言，文件传输要保证可靠性 (文件传输不能有差错)，对实时性要求不高(可以有大的延迟或延迟抖动)。因此FTP业务 是基于TCP协议而实现的。 FTP在用户下载时需要提供用户名的口令；即使是匿名登录，其实本质上也是有用户名 (anonymous)和口令(任意邮箱格式 xxx@xx.xxx )。 第24题：下列对集成服务(IntServ)模型和区分服务(DiffServ)模型描述正确的是(24)。', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '综合业务模型和分类业务模型的结合 这两种技术可以统合起来形成支持QoS敏感(aware)型IP业务的网络模型。在IETF给出 的框架中，端到端的QoS是由网络边缘的IntServ区域与网络核心的DiffServ区域—起提 供的，这一方式常被称为“核心边缘”方式。 第25题：MPLS是一种将(25) 路由 结合起来的集成宽带 网络技术 。 第二层转发和第三层', "["[['A. 第一层转发和第二层", "B.", "C. 第三层转发和第四层", "D. 第四层转发和第七层']]"]", 'B', '本题考查对MPLS技术核心思想的理解。 MPLS最初是基于ATM技术发展起来的。它结合ATM技术和IP技术各自的优点。其核心 思想是：边缘路由，核心交换。从协议层次上来观察即为：结合了第二层转发和第三层 路由的集成宽带网络技术。 第26题：在一个 局域网 上，进行 IPv4 动态地址自动配置的 协议 是 DHCP 协议 。 DHCP 协议 可 以动态配置的信息是(26)。', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '1000Mbps共享式以太网 如果使用共享式1000Mbps以太网(通信介质UTPcat5)组网，只能使用一个中继器。单 段连网(不使用连网设备)距离为100m。则最大联网距离为200m。 实际上，1000Mbps铜线以太网，一般使用超5类和6类UTP作为通信介质。', "["[['A.  MAC地址", "B.  CSMA/CD", "C. 通信介质", "D. 网桥协议']]"]", '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '网桥协议的问题和连网距离 STA运行需要二层设备不断交换链路信息(物理连接的信息)，其有信息广播的周期和 STA算法收敛速度的问题。如果用二层设备组网的规模过大，信息传播和算法收敛将变 的不可预测。按经验原则(无理论证明)，一般二层设备组网最大可到7级左右(7个二层设 备级联)。 第31题：VLAN实施的前提条件是(31)。', "["[['A.  使用CSMA/CD协议", "B. 基于二层设备实现", "C. 基于二层交换机实现", "D. 基于路由器实现']]"]", 'C', '本题考查VLAN的概念和实现基础。 VLAN是在二层实现的，是基于二层交换设备实现的。在普通的网桥上(非交换式)将无 法实现VLAN。 第32题：在 以太网 半双工 共享式连接中，我们无需流量控制；而在 全双工 交换式连接中要考 虑流量控制，其原因是(32)。', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '252.0。 第35题：应用MPLS VPN 时，针对每个 VPN 地址规划应满足的条件是(35)。不同的 VPN 信息 通过MPLS 骨干网 (或核心网)时通过(36)进行区分。', "["[['A. 每个VPN都是独立的，可以使用任何地址，只要保证在VPN内部合法正确即可", "B. VPN之间的地址不能相互重叠", "C. VPN内只能使用公网IP地址", "D. VPN内只能使用私网IP地址']]"]", 'A', '本题考查VPN的概念和MPLS VPN的工作原理。', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '结论 VPN是用户的专用网络，因此每个VPN是独立的。如果每个VPN是独立的，就存在地 址重叠问题，即两个或多个VPN内部的地址信息是重叠的，此时只传递VPN内部的路由 信息就无法正常进行选路。 要在存在地址重叠的MPLS三层VPN的MPLS骨干(或称核心)网上正确传递VPN路由，就 必须传递两个信息：VPN内部的路由信息(用IP地址标识)和VPN的标识，其中VPN标识 用于PE之间识别要传递到那些VPN，IP地址(包括子网标识)用于传递VPN内部的路由信 息。 第36题：应用MPLS VPN时，针对每个VPN地址规划应满足的条件是(35)。不同的VPN信息 通过MPLS骨干网(或核心网)时通过(36)进行区分。', "["[['A.  IP地址+AS号", "B. IP地址+子网掩码", "C. VPN标识符", "D. VPN标识符+IP地址']]"]", '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '结论 VPN是用户的专用网络，因此每个VPN是独立的。如果每个VPN是独立的，就存在地 址重叠问题，即两个或多个VPN内部的地址信息是重叠的，此时只传递VPN内部的路由', "["[['A. 从乙用户所在的物理网络的物理层开始检查故障，依次检测物理层、数据链路层、网", "B. 从乙用户所在的物理网络的路由器开始检查故障，依次检测路由器，二层交换机、中", "C. 从检测公司的服务器开始，依次检测服务器、网络互联设备、物理层连接", "D. 从甲用户所在的物理网络首先开始检测，依次检测物理层、数据链路层、网络层直到']]"]", '', '', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '与具体互联网业务相结合。 E-mail：发送邮件和接收邮件。视为对等流量，即50%流出，50%流入。 Web：浏览网络，从web下载的流量大。使用20/80法则。流出：20%，流入80%。 本题答案：流出流量：30×1×50%+30×0.5×20%=18Mbps。 第39题：在采用公开 密钥 密码体制 的 数字签名 方案中，每个用户有一个 私钥 ，可用它进行 (39)；同时每个用户还有一个 公钥 ，可用于(40)。', "["[['A. 解密和验证", "B. 解密和签名", "C. 加密和签名", "D. 加密和验证']]"]", 'B', '本题考查公开密钥密码体制的基础知识。 与只使用一个密钥的对称传统密码不同，公钥密码学是非对称的，它依赖于一个公开密 钥和一个与之在数学函数上相关但不相同的私钥。由于公钥可以对外公开，通常用于加 密和签名认证(这样与之通信的多个用户可以共用一个加密密钥，密钥管理开销小)，私 钥是用户自己保管的，通常用于解密和签名。', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '7，业务发展差的概率为0.3。现有三种规划方案可供选择： 方案1，直接投资3000万元大规模建网。若业务发展得好，每年可获利1000万元，若业务发 展不好，每年亏损200万元，服务期为10年； 方案2，投资1400万元建设小规模 网络 。若业务发展得好，每年可获利400万元，若业务发展 不好，每年仍可获利300万元，服务期为10年； 方案3，前3年按方案2实施，即先投资1400万元建设小规模 网络 ， 收益 同方案2。3年后若业 务发展不好，则继续按方案2实施；若业务发展得好，则再追加投资2000万元进行 网络 扩 容，扩容后服务期为7年，每年可获利950万元。 根据以上条件经计算可知(70)。', "["[['A. 方案1的期望净收益为5000万元", "B. 方案3的期望净收益为3595万元", "C. 方案1为最优方案", "D. 方案2为最优方案']]"]", 'B', '本题考查风险型决策方法和概率相关的基础知识。 在风险型决策问题中，各种方案的实施在不同的条件下所导致的后果是不一样的，而各 种条件和后果出现的概率是可以测算的，决策者可以通过计算出各方案在不同条件下的 期望收益来考虑未来的经济效果。针对本题分别计算三种方案的期望净收益，期望净收 益最大的为最优方案。 该方案1的期望净收益为：', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '7×(400×3-2000+950*7)+0.3×300×10-1400=3595(万元)。 计算结果表明，方案3的期望净收益最大，因此，方案3为最优方案。 第71题：A glue that holds the whole Internet together is the network layer protocol, (71) . Unlike most older network layer protocols, it was designed from the beginning with internetworking in mind. Its job is to provide a (72) way to transport datagrams from source to destination, without regard to whether these machines are on the same network or whether there are other networks in between them. Communication in the Internet works as follows. The (73) layer takes data streams and breaks them up into datagrams. Each datagram is transmitted through the Internet, possibly being fragmented into smaller units as it goes. When all the pieces finally get to the destination machine, they are reassembled by the (74) layer into the original datagram. This datagram is then handed to the transport layer, which inserts it into the receiving process’ input stream. An IP datagram consists of a header part and a text part. The header has a (75) part and a variable length optional part.', "["[['A. IP (Internet Protocol)", "B. IP (Interworking Protocol)", "C.  TCP (Transport Control Protocol)", "D.  TCP (Transfer Communication Protocol)']]"]", 'A', '将整个互联网连成一体的是网络层协议(71)。与大多数更早的网络层协议不同,它在设计 之初就充分考虑了网络互连。它负责提供一种(72)的方式，从信源到信宿传递数据报， 不管信源和信宿机器是否在同一个网络中，或者它们之间是否有其他网络。互联网中的 通信遵照以下方式进行。(73)层将数据流分割成数据报，每个数据报通过互联网传输的 过程中，有可能被分割成更小的单元。当所有的数据单元最终到达目的地主机时，它们 被(74)层重新组合成原始数据报。这个数据报随后被提交给传输层，由传输层将其插入 接收进程的输入流中。一个IP数据报包含报头和报文两部分。报头包括一个(75)部分和 一个可变长度的可选部分。 第72题：A glue that holds the whole Internet together is the network layer protocol, (71) . Unlike most older network layer protocols, it was designed from the beginning with internetworking in mind. Its job is to provide a (72) way to transport datagrams from source to destination, without regard to whether these machines are on the same network or whether there are other networks in between them.', 2, '2011年综合知识', '2011,综合知识', 2011);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0.0的路径，结果导致目标地址为10.4.0.0的数据包在三个路由器之间来回传递，从 而形成路由环路，直到路由度量达到最大值才能发现网络故障。 解决路由环路问题可以采用水平分割法（Split Horizon)。这种方法规定，路由器必须 有选择地将路由表中的信息发送给邻居，而不是发送整个路由表。具体地说，一条路由 信息不会被发送给该信息的来源。可以对上图中R2的路由表项将加上一些注释，这样， 每一条路由信息都不会通过其来源接口向回发送，就可以避免环路的产生。', "["[['A. OSPF是一种应用于不同自治系统之间外部网关协议", "B. OSPF是基于相邻结点的负载来计算最佳路由", "C. 在OSPF网络中，不能根据网络的操作状态动态改变路由", "D. 在OSPF网络中，根据链路状态算法确定最佳路由']]"]", '', '', 2, '2012年综合知识', '2012,综合知识', 2012);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '133.0/24，如果进行 路由 汇聚，能覆盖这4条 路由 的地址是（37)。', "["[['A. 172.118.128.0/21", "B. 172.118.128.0/22", "C. 172.118.130.0/22", "D. 172.118.132.0/20']]"]", 'A', '地址172.118.129.0/24的二进制形式为 10101100 01110110 10000001 00000000 地址172.118.130.0/24的二进制形式为 10101100 01110110 10000010 00000000 地址172.118.132.0/24的二进制形式为 10101100 01110110 10000100 00000000 地址172.118.133.0/24的二进制形式为 10101100 01110110 10000101 00000000 地址172.118.128.0/21的二进制形式为 10101100 01110110 10000000 00000000 所以能覆盖这4条路由的地址是172.118.128.0/21 。 第38题：属于 网络', 2, '2012年综合知识', '2012,综合知识', 2012);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '200.0/21的地址是（38)', "["[['A. 202.117.198.0", "B. 202.117.206.0", "C. 202.117.217.0", "D. 202.117.224.0']]"]", 'B', '地址202.117.200.0/21的二进制形式为：11001010011101011100100000000000 。', 2, '2012年综合知识', '2012,综合知识', 2012);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '224.0的二进制形式为：11001010011101011110000000000000。 可以看出202.117.206.0属于网络202.117.200.0/21 。 第39题：下面的地址中，属于 单播 地址的是（39)。', "["[['A. 172.31.128.255/18", "B. 10.255.255.255", "C. 172.160.24.59/30", "D. 224.105.5.211']]"]", '', '', 2, '2012年综合知识', '2012,综合知识', 2012);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5G系统能够提供3G系统中才有的一些功能，例如分组交换业务，也能共享2G时代开发 出来的TDMA或CDMA网络。GPRS分组网络重叠在GSM网络之上，利用GSM网络中未 使用的TDMA信道，为用户提供中等速度的移动数据业务。 GPRS是基于分组交换的技术，多个用户可以共享带宽，每个用户只有在传输数据时才会 占用信道，所有的可用带宽可以立即分配给当前发送数据的用户，适合于Web浏览、E- mail收发和即时消息那样的共享带宽的间歇性数据传输业务。通常，GPRS系统是按交换 的字节数计费，而不是连接时间计费。GPRS系统支持IP协议和PPP协议。理论上的分组 交换速度大约是170kb/s,而实际速度只有30?70kb/s。 对GPRS的射频部分进行改进的技术方案称为增强数据速率的GSM演进 (Enhanced Datarates for GSM Evolution,EDGE)。EDGE又称为增强型 GPRS(EGPRS：" ,可以工作在已经部署GPRS的网络上，只需要对手机和基站设备做一些 简单的升级。EDGE被认为是2.75G技术，采用8PSK的调制方式代替了GSM使用的高斯最 小移位键控（GMSK)调制方式，使得一个码元可以表示3比特信息。理论上说，EDGE提 供的数据速率是GSM系统的3倍。2003年EDGE被引入北美的GSM网络，支持从20? 200kb/s的高速数据传输，最大数据速率取决于同时分配到的TDMA帧的时隙的多少。 第23题：IEEE802.3规定的CSMA/CD 协议 可以利用多种监听 算法 来减小发送 冲突 的概率，下面 关于各种监听 算法 的描述中，正确的是（23)。', "["[['A. 非坚持型监听算法有利于减少网络空闲时间", "B. 坚持型监听算法有利于减少冲突的概率", "C. P 坚持型监听算法无法减少网络的空闲时间", "D. 坚持型监听算法能够及时抢占信道']]"]", 'D', '以太网的监听算法分为3种： 非坚持型监听算法可以最大限度地减少冲突概率，但是可能会延迟发送，引起带宽的浪 费；坚持型监听算法能及时抢占信道，但是会增加冲突的概率。P-坚持型监听算法既可以', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '停止系统服务中的（31)服务。', "["[['A. nslookup", "B. ipconfig/renew", "C. ipconfig/flushdns", "D. ipconfig/release']]"]", 'C', '本题考查DNS服务器及其原理。 当DNS服务器更新了某域名的IP地址后，客户端可能由于缓存中的域名记录尚未更新，无 法访问网站，此时可以通过命令ipconfig/flushdns或停止服务DNSClient来更新。 第31题：如果DNS服务器更新了某域名的IP地址，造成客户端无法访问网站，在客户端通常有 两种方法解决此问题：', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '停止系统服务中的（31)服务。', "["[['A.  SNMP Client", "B.  DNS Client", "C. Plug and Play", "D.  Remote Procedure Call (RPC)']]"]", 'B', '本题考查DNS服务器及其原理。 当DNS服务器更新了某域名的IP地址后，客户端可能由于缓存中的域名记录尚未更新，无 法访问网站，此时可以通过命令ipconfig/flushdns或停止服务DNS Client来更新。', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '01000011.00100001的 数据报 ，则该 数据报 应送给用户（38)。', "["[['A. 4", "B. 8", "C. 10", "D. 16']]"]", 'D', '用户U1有4000台主机，则必须给他分配16个C类网络（256X16)，则指定给U1的地址掩 码应为255.255.240.0。 给用户U2分配的C类网络号为196.25.16.0?196.25.31.0,其中包含16八C类网络，所以用 户U2的地址掩码应为255.255.240.0。 用户U1的网络地址196.25.64.0/20：11000100.00011001.01000000.00000000 用户U2的网络地址196.25.64.0/20：11000100.00011001.00100000.00000000 路由器收到的数据报目标地址为： 11000100.00011001.01000011.00100001 根据最长匹配原则，该数据报应送给用户U1。 第36题：采用可变长子网掩码可以把大的网络划分成小的子网，或者把小的网络汇聚成大的超 网。假设用户U1有4000台主机，则必须给他分配（35)个C类网络，如果分配给用户U1的超网 号为196.25.64.0,则指定给U1的地址掩码为（36);假设给用户U2分配的C类网络号为', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '01000011.00100001的数据报，则该数据报应送给用户（38)。', "["[['A. 255.255.255.0", "B. 255.255.250.0", "C. 255.255.248.0", "D. 255.255.240.0']]"]", 'D', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '01000011.00100001的数据报，则该数据报应送给用户（38)。', "["[['A. 255.255.255.0", "B. 255.255.250.0", "C. 255.255.248.0", "D. 255.255.240.0']]"]", 'D', '用户U1有4000台主机，则必须给他分配16个C类网络（256X16)，则指定给U1的地址掩 码应为255.255.240.0。 给用户U2分配的C类网络号为196.25.16.0?196.25.31.0,其中包含16八C类网络，所以用 户U2的地址掩码应为255.255.240.0。 用户U1的网络地址196.25.64.0/20：11000100.00011001.01000000.00000000 用户U2的网络地址196.25.64.0/20：11000100.00011001.00100000.00000000 路由器收到的数据报目标地址为： 11000100.00011001.01000011.00100001 根据最长匹配原则，该数据报应送给用户U1。 第38题：采用可变长子网掩码可以把大的网络划分成小的子网，或者把小的网络汇聚成大的超 网。假设用户U1有4000台主机，则必须给他分配（35)个C类网络，如果分配给用户U1的超网 号为196.25.64.0,则指定给U1的地址掩码为（36);假设给用户U2分配的C类网络号为', 2, '2013年综合知识', '2013,综合知识', 2013);
