INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '10.1的WWW服务”的是 (41)。 access-list 101 permit tcp any host 202.110.10.1 eq www', "["[['A. access-list 101 permit any 202.110.10.1", "B.", "C. access-list 101 deny any 202.110.10.1", "D. access-list 101 deny tcp any host 202.110.10.1 eq www']]"]", 'B', '本题考查ACL语句。 正确的ACL语句为：access-list 101 permit tcp any host 202.110.10.1 eq www。 第42题： SSL 协议 共有上下两层组成，处于下层的是（42)。', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '11b工作在2.4G频段、最高速率11兆、目前已经逐步被淘汰；802.11g工作在2.4G频 段、最髙速率54兆；802.11n工作在2.4GHz或者5GHz、最高速率可达600兆。因此 IEEE802.11b/g/n，采用的共同工作频带为2.4GHz。 第65题：在进行无线WLAN网络建设时，现在经常使用的协议是IEEE 802.11b/g/n，采用的共 同工作频带为（64)。其中为了防止无线信号之间的干扰，IEEE将频段分为13个信道，其中仅有 三个信道是完全不覆盖的，它们分别是（65)。', "["[['A. 信道1、6和13", "B. 信道1、7和11", "C. 信道1、7和13", "D. 信道1、6和11']]"]", '', '', 2, '2013年综合知识', '2013,综合知识', 2013);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '16.0/24到172.30.31.0/24的分组通过 路由器 ，则对应 ACL语句应该是（ ）。', "["[['A. access-list 10 permit 172.30.16. 0 255.255. 0.0", "B. access-list 10 permit 172.30.16. 0 0.0.255.255", "C. access-list 10 permit 172.30.16. 0 0.0.15.255", "D. access-list 10 permit 172.30.16. 0 255.255.240.0']]"]", 'C', '如果允许来自子网172.30.16.0/24到172.30.31.0/24的分组通过路由器，则对应的ACL 语句应该是access-list 10 permit 172.30.16.0 0.0.15.255。值得注意的是反掩码', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '15.255正好覆盖了172.30.16.0网络中最后12位表示的全部地址。 第24题：结构化布线系统分为六个 子系统 ，其中水平 子系统 （ ）。', "["[['A. 由各种交叉连接设备以及集线器和交换机等交换设备组成", "B. 连接干线子系统和工作区子系统", "C. 由终端设备到信息插座的整个区域组成", "D. 实现各楼层设备间子系统之间的互连']]"]", 'B', '结构化布线系统分为6个子系统：工作区子系统、水平子系统、管理子系统、干线 (或垂 直）子系统、设备间子系统和建筑群子系统。其中水平子系统是指各个楼层接线间的配', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '133.0/24，如果进行 路由 汇聚，能覆盖这4条 路由 的地址是（ ）。', "["[['A. 210.114.128.0/21", "B. 210.114.128.0/22", "C. 210.114.130.0/22", "D. 210.114.132.0/20']]"]", 'A', '展开IP地址的第3字节如下： 第1条路由：10000001 第2条路由：10000010 第3条路由：10000100 第4条路由：10000101 聚合之后该字节前5比特网络号，后3比特主机号，即网络号210.114.128.0,掩码长度21 位。 第38题：下面地址中属于 单播 地址的是（ ）。', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '17.255/22是什么地址？（ ）。', "["[['A. 网络地址", "B. 全局广播地址", "C. 主机地址", "D. 定向广播地址']]"]", 'C', 'IP地址202.117.17.255/22 的二进制形式是', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '000100,主机号是01.11111111。 第40题： IPv6 地址的格式前缀用于表示地址类型或 子网 地址，例如60位的地址前缀 10DE00000000CD3有多种合法的表示形式，以下选项中，不合法的是（ ）。', "["[['A.  10DE:0000: 0000:CD30: 0000:0000:0000:000/60", "B.  10DE::CD30:0:0:0:0/60", "C.  10DE: 0:0:CD3/60", "D.  10DE: 0:0:CD3::/60']]"]", 'C', '以上IPv6地址前缀中不合法的是10DE:0:0:CD3/60，因为这种表示可展开为 10DE:0000:0000:0000:0000:0000:0000:0CD3，另外CD30也变成了0CD3,这些都是 错误的。 第41题：下列 攻击 方式中，（ ）不是利用TCP/IP漏洞发起的 攻击 。', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '4GHz频段划分出13个信道，而这13个信道中有相互覆盖和相互重叠的情况，为了无 线网络能够互不干扰的工作，在13个信道中，只有3个信道可用，1、6、11号信道。 第56题：目前大部分 光缆 工程 测试 都采用OTDR（光时域反射计）进行 光纤 衰减的 测试 ， OTDR通过检测来自 光纤 的背向散射光进行 测试 。这种情况下采用（ ）方法比较合适。', "["[['A. 双向测试", "B. 单向测试", "C. 环形测试", "D. 水平测试']]"]", '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5E07.FFFF。', "["[['A. R1与R2、R3的物理链路连接不稳定", "B. R1未能完整的学习到R2和R3的局域网路由", "C. 管理员手工地对R2和R3进行了路由汇总", "D. RIP协议版本配置错误，RIPv1不支持不连续子网']]"]", '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '3.0/24路由进行了路由汇总，统一汇总成172.16.0.0/16路由，因此，当从R1 ping R2或者R3时，路由器认为从R1与R2和R3相连的接口均可到达，实现了不恰当的 负 载均衡。 第65题：使用长度1518字节的帧 测试 网络吞吐量时，1000M 以太网 抽样 测试 平均值是（ ） 时，该 网络设计 是合理的。', "["[['A. 99%", "B. 80%", "C. 60%", "D. 40%']]"]", '', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5/125μm多模光纤的最大传输距离为220m，使用50/125μm多模光纤的域大传输 距离为500 米。因此只需要将两栋楼之间的多模光纤更换为50/125μm多模光纤即可。 第67题：IANA在可聚合全球 单播 地址 范围 内指定了一个格式前缀来表示 IPv6 的6to4地址， 该前缀为（ ）。', "["[['A. 0x1001", "B. 0x1002", "C. 0x2002", "D. 0x2001']]"]", 'C', '', 2, '2014年综合知识', '2014,综合知识', 2014);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '832。 第10题：软件设计师王某在其公司的某一综合 信息管理系统 软件开发 项目中、承担了大部分 程序设计 工作。该系统交付用户，投入试运行后，王某辞职离开公司，并带走了该综合 信息 管理系统 的 源程序 ，拒不交还公司。王某认为综合 信息管理系统 源是他独立完成的，他是综 合 信息管理系统 源程序 的 软件著作权人 。王某的行为（10）。', "["[['A. 侵犯了公司的软件著作权", "B. 未侵犯公司的软件著作权", "C. 侵犯了公司的商业秘密权", "D. 不涉及侵犯公司的软件著作权']]"]", 'A', '本题考查知识产权基本知识。 《计算机软件保护条例》第13条规定“自然人在法人或者其他组织中任职期间所开发的 软件有下列情形之一的，该软件著作权由该法人或者其他组织享有，该法人或者其他组 织可以对开发软件的自然人进行奖励： (一)针对本职工作中明确指定的开发目标所开发的软件； (二)开发的软件是从事本职工作活动所预见的结果或者自然的结果； (三)主要使用了法人或者其他组织的资金、专用设备、未公开的专门信息等物质技术条 件所开发并由法人或者其他组织承担责任的软件。” 根据《计算机软件保护条例》规定，可以得出这样的结论，当公民作为某单位的职工 时，如果其开发的软件属于执行本职工作的结果，该软件著作权应当归单位享有。而荜 位可以给予开发软件的职工奖励。需要注意的是，奖励软件开发者并不是单位的一种法 定义务，软件开发者不可援引《计算机软件保护条例》强迫单位对自己进行奖励。 王某作为公司的职员，完成的某一综合信息管理系统软件是针对其本职工作中明确指定', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '记账(Accounting):记录用户使用网络资源的情况。 通常用来实现AAA服务的协议是RADIUS(Remote Authentication Dial In User Service)协议，这是基于UDP的一种客户机/服务器协议。RADIUS客户机是网络访问服 务器，它通常是一个路由器、交换机或无线访问点。RADIUS服务器通常是在UNIX或 Windows 2000服务器上运行的一个监护程序。 第22题：AAA服务器（AAA server）是一种处理用户访问请求的框架协议，它主要功能有3 个，但是不包括（21），通常用来实现AAA服务的协议是（22）。', "["[['A. Kerberos", "B.  RADIUS", "C. SSL", "D. IPSec']]"]", 'B', 'AAA服务器的主要目的是管理用户访问网络服务器权限，具体为：', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '记账(Accounting):记录用户使用网络资源的情况。 通常用来实现AAA服务的协议是RADIUS(Remote Authentication Dial In User Service)协议，这是基于UDP的一种客户机/服务器协议。RADIUS客户机是网络访问服 务器，它通常是一个路由器、交换机或无线访问点。RADIUS服务器通常是在UNIX或 Windows 2000服务器上运行的一个监护程序。 第23题：由无线终端组成的MANET 网络 ，与固定 局域网 最主要的区别是（23），在下图所 示的由A、B、C三个结点组成的MANET中，圆圈表示每个结点的发送 范围 ，结点A和结点C 同时发送 数据 ，如果结点B不能正常接收，这时结点C称为结点A的（24）。', "["[['A. 无线访问方式可以排除大部分网络入侵", "B. 不需要运行路由协议就可以互相传送数据", "C. 无线信道可以提供更大的宽带", "D. 传统的路由协议不适合无线终端之间的通信']]"]", 'D', 'IEEE802.il标准定义的AdHoc网络是由无线移动结点组成的对等网，无须网络基础设施 的支持，能够根据通信环境的变化实现动态重构，提供基于多跳无线连接的分组数据传 输服务。在这种网络中，每一个结点既是主机，又是路由器，它们之间相互转发分组， 形成一种自组织的MANET(Mobile Ad Hoc Network)网络。 与传统的有线网络相比，MANET有如下特点： ?网络拓扑结构是动态变化的，由于无线终端的频繁移动，可能导致结点之间的相互位 置和连接关系难以维持稳定。 ?无线信道提供的带宽较小，而信号衰落和噪声干扰的影响却很大。由于各个终端信号 覆盖范围的差别，或者地形地物的影响，还可能存在单向信道。 ?无线终端携带的电源能量有限，应采用最节能的工作方式，因而要尽量减小网络通信 开销，并根据通信距离的变化随时调整发射功率。 ?由于无线链路的开放性，容易招致网络窃听、欺骗、拒绝服务等恶意攻击的威胁，所 以需要特别的安全防护措施。 路由算法是MANET网络中重要的组成部分，由于上述特殊性，传统有线网络的路由协 议不能直接应用于MANET。IETF成立的MANET工作组开发了MANET路由规范，使其 能够支持包含上百个路由器的自组织网络，并在此基础上开发支持其他功能的路由协', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5.40：1101 1100.0111 0011.0000 0101.0010 1000 第38题：主机地址122.34.2.160属于 子网 （38）。', "["[['A. 122.34.2.64/26", "B. 122.34.2.96/26", "C. 122.34.2.128/26", "D. 122.34.2.192/26']]"]", 'C', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '选择e，使e×d=1(mod z) 明文P被分成k位的块，k是满足2 k <n的最大整数，于是有0≤P<n。加密时计算 C=P e (mod n) 这样公钥为(e，n)。解密时计算 P=C d (mod n) 即私钥为(d，n)。 第42题：按照RSA算法，取两个最大素数p和q，n=p*q，令φ(n)=(p-1)*(q-1)，取与φ(n)互 质的数e，d=e - mod φ(n)，如果用M表示消息，用C表示密文，下面（41）是加密过程， （42）是解密过程。', "["[['A.  M=C", "B.  M=C", "C.  M=C", "D.  M=C']]"]", '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '选择e，使e×d=1(mod z) 明文P被分成k位的块，k是满足2k<n的最大整数，于是有0≤P<n。加密时计算 C=P e (mod n) 这样公钥为(e，n)。解密时计算 P=C d (mod n) 即私钥为(d，n)。 第43题：A和B分别从CA1和CA2两个认证中心获取了自己的证书IA和IB，要使A能够对B进行 认证，还需要（43）。', "["[['A.  A和B交换各自公钥", "B.  A和B交换各自私钥", "C.  CA1和CA2交换各自公钥", "D.  CA1和CA2交换各自私钥']]"]", 'C', '本题考查CA数字证书认证的基础知识。 CA为用户产生的证书应具有以下特性。 ①只要得到CA的公钥，就能由此得到CA为用户签署的公钥。 ②除CA外，其他任何人员都不能以不被察觉的方式修改证书的内容。 如果所有用户都由同一CA签署证书，则这一CA就必须取得所有用户的信任。如果用户 数量很多，仅一个CA负责为所有用户签署证书就可能不现实。通常应有多个CA，每个', 2, '2015年综合知识', '2015,综合知识', 2015);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '240.0，那么地址的范围是：202.117.0.0——202.117.15.254。 第28题：某网络的地址是202.117.0.0，其中包含4000台主机，指定给该网络的合理子网掩码是 （27） ，下面选项中，不属于这个网络的地址是（28）。', "["[['A. 202.117.0.1", "B. 202.117.1.254", "C. 202.117.15.2", "D. 202.117.16.113']]"]", 'D', '', 2, '2016年综合知识', '2016,综合知识', 2016);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '240.0，那么地址的范围是：202.117.0.0——202.117.15.254。 第29题：在大型 网络 中，为了有效减少 收敛时间 ，可以采用的 路由协议 配置方法是（29）。', "["[['A. 为存根网络配置静态路由", "B. 增加路由器的内存和处理能力", "C. 所有路由器都配置成静态路由", "D. 减少路由器之间的跳步数']]"]", 'A', '存根网络是一种通过单一路由访问的网络。是指与外界只有一个输出连接的网络，在存根网 络里面，可以使用默认路由。可以有效减少收敛时间。 第30题：浏览网页时 浏览器 与Web 服务器 之间需要建立一条TCP连接，该连接中 客户端 使用的 端口 是（30）。', 2, '2016年综合知识', '2016,综合知识', 2016);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '133.0/24，在 路由器 中汇聚成一条路由，该路由的 网络地址 是（ ）。', "["[['A. 202.114.128.0/21", "B. 202.114.128.0/22", "C. 202.114.130.0/22", "D. 202.114.132.0/20']]"]", 'A', '任意播地址是一个标识符对应多个接口的情况。如果一个数据报文要求被传送到一个任意点 地址，则将被传送到最近一个接口（路由器决定）。 第32题：RIPv2对RIPv1 协议 的改进之一是采用 水平分割法 。以下关于 水平分割法 的说法中错误的 是（ ）。', 2, '2017年综合知识', '2017,综合知识', 2017);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '采用测试软件输入网站 www.xxx.com/index.action. 执行ifconfig 命令，结果如图3-2所示。', "["[['A. Java反序列化", "B. 跨站脚本攻击", "C. 远程命令执行", "D. SQL 注入']]"]", '', '', 2, '2017年综合知识', '2017,综合知识', 2017);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '通过浏览器访问网站管理系统，输入 www.xxx.com/login?f_page=-->" "><svg onload=prompt(/x/)>，结果如图 3-3 所示。 从图 3-3 可以看出，该网站存在（ ）漏洞，靖针对该漏洞提出相应防范措施。 备选答案： 答案', "["[['A. Java反序列化", "B. 跨站脚本攻击", "C. 远程命令执行", "D. SQL注入']]"]", '', '（1）主机 （2）物理 （3）应用 （4）网络', 2, '2017年综合知识', '2017,综合知识', 2017);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '17.255/22主机位非全0和全1，是一个主机地址。 第25题：地址202.118.37.192/26是(24)，地址192.117.17.255/22是(25)。', "["[['A. 网络地址", "B. 组播地址", "C. 主机地址", "D. 定向广播地址']]"]", '', '', 2, '2018年综合知识', '2018,综合知识', 2018);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '17.255/22主机位非全0和全1，是一个主机地址。 第26题：将地址块192.168.0.0/24按照可变长 子网掩码 的思想进行子网划分，若各部门可用 主机地址 需求 如下表所示，则共有(26)种划分方案，部门3的掩码长度为(27)。', "["[['A. 4", "B. 8", "C. 16", "D. 32']]"]", 'C', '', 2, '2018年综合知识', '2018,综合知识', 2018);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0.0/24先划分2个子网，1个子网给部门1，这里有2种情况，第二个子网再划 分2个子网，1个子网给部门2，这里又是2种情况，剩下的子网再划分2个子网，一个分 给部门3，还是2种情况，最后剩下的子网再分2个子网，一个给部门4、一个给部门5， 也是2种情况。 所以总的划分方案就是2*2*2*2=16种。其中部门3的主机只有16台，所以只需要5位主 机位，掩码长度32-5-27即可。 第27题：将地址块192.168.0.0/24按照可变长子网掩码的思想进行子网划分，若各部门可用 主机地址需求如下表所示，则共有(26)种划分方案，部门3的掩码长度为(27)。', "["[['A. 25", "B. 26", "C. 27", "D. 28']]"]", 'C', '', 2, '2018年综合知识', '2018,综合知识', 2018);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0.0/24先划分2个子网，1个子网给部门1，这里有2种情况，第二个子网再划 分2个子网，1个子网给部门2，这里又是2种情况，剩下的子网再划分2个子网，一个分 给部门3，还是2种情况，最后剩下的子网再分2个子网，一个给部门4、一个给部门5， 也是2种情况。 所以总的划分方案就是2*2*2*2=16种。其中部门3的主机只有16台，所以只需要5位主 机位，掩码长度32-5-27即可。 第28题：若一个 组播组 包含6个成员， 组播服务器 所在 网络 有2个 路由器 ，当 组播服务器 发送 信息时需要发出()个分组。', "["[['A. 1", "B. 2", "C. 3", "D. 6']]"]", 'A', '组播就是一组特定的对象，不管该组特定对象包含有多少个成员，针对一个组播服务只 需要发送一个组播包，组内成员都会收到。 第29题：在BGP4 协议 中，当出现 故障 时采用() 报文 发送给邻居。', 2, '2018年综合知识', '2018,综合知识', 2018);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '进程 P 有 8 个页面，页号分别为 0-7，页面大小为 4K，假设系统给进程 P 分配了 4 个存 储块 P， 进程P 的页面变换表如下所示。 表中状态位等于1 和 0 分别表示页面在内存和不在 内存。 若进程P 要访问的逻辑地址为十六进制 5148H， 则该地址经过变换后， 其物理地址应 为十六进制 （ ） ； 如果进程P 要访问的页面 6 不在内存， 那么应该淘汰页号为 （ ） 的页面。 页号 页帧号 状态位 访问位 修改位 0 -- 0 0 0 3 -- 0 0 0 4 -- 0 0 0 6 -- 0 0 0', "["[['A.3148H", "B.5148H", "C.7148H", "D.9148H']]"]", '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '数据库的安全机制中，通过提供（ ）第三方开发人员调用进行数据更新，从而保证数据 库的关系模式不被第三方所获取。', "["[['A.索引", "B.视图", "C.存储过程", "D.触发器']]"]", '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '信息系统规划方法中，关键成功因素法是通过对关键成功因素的识别，找出实现目标所 需要的关键信息集合，从而确定系统开发的（ ） ，关键成功因素来源于组织的目标，通过 组织的目标分解和关键成功因素识别、 （ ）识别，一直到产生数据字典。', "["[['A.系统边界", "B.功能指标", "C.优先次序", "D.性能指标']]"]", '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '软件概要设计将软件需求转化为（ ）和软件的（ ）。', "["[['A.算法流程", "B.数据结构", "C.交互原型", "D.操作接口']]"]", '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '软件性能测试有多种不同类型测试方法， 其中， （ ） 用于测试在系统资源特别少的情况 下考查软件系统运行情况； （ ）用于测试系统可处理的同时在线的最大用户数量。', "["[['A.强度测试", "B.负载测试", "C.压力测试", "D.容量测试']]"]", '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '著作权中， （ ）的保护期不受期限。', "["[['A.发表权", "B.发行权", "C.展览权", "D.署名权']]"]", '', '', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '在 HFC 网络中，Internet 接入采用的复用技术是（ ） ，其中下行信道不包括（ ）。 2019 年下半年网络规划设计师上午真题及答案', "["[['A.FDM", "B.TDM", "C.CDM", "D.STDM']]"]", '', '解析： 5148H 转换为十进制 20808，20808 除以 4096（4K）商 5 余 328，商 5 表示 5148H 对应的页 号为 5 号页，页内位置为 328。根据页表对应关系 5 号页对应 3 号物理块（页帧号） ，所以 此逻辑地址对应的物理地址：3*4096+328=12616，转十六进制为：3148H. 页面淘汰算法按照程序的局部性原理， 优先淘汰最近没有访问过的。 如果都访问过， 优先淘 汰没有修改过的。所以优先淘汰 2 号页。 二、小任老师网络工程师视频教程 小任老师网络工程师视频教程', 2, '2019年综合知识', '2019,综合知识', 2019);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0kHz；ADSL 利用回声抵消，可实现上行和下行同时传输，且速率非对称，上行与下 行信道频率可部分重叠。 summer孇X Q èDe 18、以太网交换机中采用生成树算法是为了解决(18)问题。 18、【答案】C 【', "["[['A.帧的转发", "B.短路", "C.环路", "D.生成转发表']]"]", '', '】送分题，必须拿分。 19、6个速率为 64Kb/s的用户按照统计时分多路复用技术(STDM)复用到一条干线上、 若每个用户平均效率为 80%，干线开销4%，则干线速率为(19) Kb/s。 19、【答案】C 【解析】网规2020 年考过的原题，干线速率计算：（64*6*80%）/（1-4%）=320Kbps 20、Internet网络核心采取的交换方式为(20)。 20、【答案】A 【解析】三种交换方式：电路交换、报文交换和分组交换，目前 Internet 应用最广的 是 IP 协议，属于分组交换。其他两种交换的特点和优缺点需要掌握。 21、以下关于虚电路交换技术的叙述中，错误的是(21)。 21、【答案】D 【解析】掌握几种交换方式。 22、SDH的帧结构包含(22)。 22、【答案】A 【解析】 summer孇X Q èDe 23、假设客户端采用持久型 HTTP 1.1 版本向服务器请求一个包含10个图片的网页。 设基页面传输时间为 Tbas，图片传输的平均时间为 Timg,客户端到服务器之间的往返 时间为 RTT，则从客户端请求开始到完整取回该网页所需时间为(23)。 23、【答案】D 【解析】根据选项倒推，10个图片，所有选项都是10Timg，即图片会请求10 次。基 础页面是1个框架，只需要请求1 次，即1xTbas，那么在A和D 中选择。根据前面推 断的10 次图片请求，1 次基础页面请求，然后包含返回的流量，即11 次往返，故 11xRTT，所以选D。 24、在CSMA/CD中，同一个冲突域中的主机连续经过3次冲突后，每个站点在接下来 信道空闲的时候立即传输的概率是(24)。 24、【答案】D 【解析】记住公式冲突概率1/2 n （n表示已经发生冲突的次数）。 25-26、在下图所示的网络拓扑中，假设自治系统AS3和AS2内部运行OSPF, AS1和 AS4内部运行 RIP。各自治系统间用BGP作为路由协议，并假设AS2和AS4 之间没有物 理链路。则路由器3c 基于(25)协议学习到网络x的可达性信息。1d通过(26)学习到x 的可达性信息。 summer孇X Q èDe 25-26、【答案】（25）C （26）B 【解析】考查基础路由学习，RIP的开销是跳数，选择跳数最小的路径。 27-28、Traceroute 在进行路由追踪时发出的 ICMP 消息(27)，收到的消息是中间节点 或目的节点返回的(28)。 27-28、【答案】（27）A （28）B 【解析】traceroute/tracert 每次发送TTL 递增的 echo Request 报文。 29、下列不属于快速 UDP 互联网连接(QUIC)协议的优势是(29)。 29、【答案】A 【解析】https://zhuanlan.zhihu.com/p/32553477 Quic相比现在广泛应用的 http2+tcp+tls 协议有如下优势[2]:', 2, '2021年综合知识', '2021,综合知识', 2021);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '前向冗余纠错。 快速 UDP 互联网连接(QUIC)协议是基于 UDP进行改造，同时具备 UDP和TCP 部分功能 的协议。虽然 UDP不提供可靠的传输，但 QUIC 在基于 UDP 之上增加了一层带来可靠性 的层。它提供了数据包重传、拥塞控制、调整传输节奏(pacing) 以及其他一些TCP 中 存在的特性。TCP 都不能纠错，很明显基于 UDP的 QUIC也不能纠错。 summer孇X Q èDe 连接迁移 TCP 连接基于四元组(源 IP、源端口、目的 IP、目的端口)，切换网络时至少会有一个 因素发生变化，导致连接发生变化。当连接发生变化时，如果还使用原来的 TCP连 接，则会导致连接失败，就得等原来的连接超时后重新建立连接，所以我们有时候发 现切换到一个新网络时，即使新网络状况良好，但内容还是需要加载很久。如果实现 得好，当检测到网络变化时立刻建立新的 TCP连接，即使这样，建立新的连接还是需 要几百毫秒的时间。 QUIC 的连接不受四元组的影响，当这四个元素发生变化时，原连接依然维持。那这是 怎么做到的呢?道理很简单，QUIC 连接不以四元组作为标识，而是使用一一个 64 位的 随机数，这个随机数被称为 Connection ID，即使IP 或者端口发生变化，只要 Connection ID 没有变化，那么连接依然可以维持。 30、对于链路状态路由算法而言，若共有 N个路由器，路由器之间共有 M条链路，则 链路状态通告的消息复杂度以及接下来算法执行的时间复杂度分别是(30)。 )和 0(N ) )和 0(M ) 30、【答案】B 【', "["[['A. O(M", "B. O(NM)和 0(N", "C. O(N", "D. O(NM)和 0(M']]"]", '', '】 31、距离向量路由协议所采用的核心算法是(31)。 31、【答案】D 【解析】距离矢量路由算法，基于 Bellman-Ford 算法。 32、IPv4 报文分片和重组分别发生在(32)。 32、【答案】B 【解析】分片发生在中间路由器，重组是在目的端。 summer孇X Q èDe 、下图为某网络拓扑的片段,将1 和 2两条链路聚合成链路 G1,并与链路3 形成 VRRP 主备关系，管理员发现在链路2 出现 CRC错误告警，此时该网络区域可能会发生的现 象是(33)。 户上网将会出现延迟卡顿 33、【答案】B 【解析】CRC 冗余告警可能是链路层有故障，导致数据丢包，从而通过链路2 的用户 会受到影响，经过链路1 的用户则无影响。 34-35、若循环冗余校验码 CRC 的生成器为 10111，则对于数据 10100010000 计算的校 验码应为(34)。该CRC 校验码能够检测出的突发错误不超过(35)。 （ 34-35、【答案】（34）A （35）B 【解析】掌握 CRC 计算过程，可以检测出小于等于校验位长度的突发错误。 36、(36)子系统是楼宇布线的组成部分。 36、【答案】C 【解析】掌握综合布线的几大子系统。 37、客户端通过 DHCP获得 IP地址的顺序正确的是(37)。 ①客户端发送DHCP REQUEST 请求 IP 地址 ②SERVER发送DHCP OFFER 报文响应 ③客户端发送DHCP DISCOVER 报文寻找DHCP SERVER ④SERVER 收到请求后回应 ACK响应请求 37、【答案】C summer孇X Q èDe 【解析】送分题，考查DHCP 过程。 38、某高校计划采用扁平化的网络结构。为了限制广播域、解决 VLAN资源紧缺的问 题，学校计划采用 QinQ(802.1Q-in-802.1Q)技术对接入层网络进行端口隔离。以下关 于 QinQ 技术的叙述中，错误的是(38)。 38、【答案】A 【解析】 • 基本 QinQ： 如果收到的是带有 VLAN Tag的报文，该报文就成为带双Tag的报 文。如果收到的是不带 VLAN Tag的报文，该报文就成为带有本端口缺省 VLAN Tag 的报文。 • 灵活 QinQ：为具有不同内层 VLAN ID的报文添加不同的外层 VLAN Tag。根据报文 内层 VLAN的802.1p 优先级标记外层 VLAN的802.1p 优先级和添加不同的外层 VLAN Tag。通过使用灵活 QinQ技术，在能够隔离运营商网络和用户网络的同时， 又能够提供丰富的业务特性和更加灵活的组网能力。 39、下面支持 IPv6的是 (39)。 39、【答案】C 【解析】支持 IPv6的路由协议：RIPng、OSPFv3、BGP4+。 40、以下关于OSPF 特性的叙述中，错误的是(40) 。 40、【答案】D 【解析】存在ABR的话，ABR是包含多个区域的LSDB，而普通的区域0的LSDB只含有 一部分LSA，就比如区域1的ABR 他的LSDB是含有区域1的LSA1和LSA2的，但是这 部分LSA是不会被传递到区域0的，所以不是所有的区域0的路由器的LSDB 都一样。 41、策略路由通常不支持根据(41)来指定数据包转发策略。 41、【答案】C 【解析】数据转发过程中，源MAC地址会发生变化。 42、SDN的网络架构中不包含(42)。 summer孇X Q èDe 42、【答案】A 【解析】SDN 实现控制层面与数据层面分离，上层是应用层。 43-44、窃取是一种针对数据或系统的(43)的攻击。DDoS 攻击可以破坏数据或系统的 (44)。 43-44、【答案】（43）B （44）A 【解析】网络安全基础。 45、以下关于 IPSec的说法中，错误的是(45) 。 45、【答案】B 【解析】IPSec 基础，必会。 46、是由我国自主研发的无线网络安全协议。 TKIP 46、【答案】A 【解析】记忆即可。 47-48、某 Web网站向 CA申请了数字证书。用户登录过程中可通过验证(47) 确认该证 书的有效性，以(48)。 47-48、【答案】（47）A （48）D 【解析】证书类似身份证，可以证实用户或网站的身份。 49、某公司要求数据备份周期为 7天，考虑到数据恢复的时间效率，需采用(49) 备 略。 49、【答案】A 【解析】完全备份恢复速度最快。 50、某网站的域名是 www.xyz.com，使用 SSL 安全页面，用户可以使用(50) 访问该网 站。 https://www.xyz.com summer孇X Q èDe 50、【答案】B 【解析】基础题，必须拿分。 51、以下关于链路加密的说法中，错误的是(51)。 51、【答案】B 【解析】链路加密如下图所示。 52-53 在运行OSPF的路由器中，可以使用(52) 命令查看OSPF进程下路由计算的统计 信息，使用(53) 命令查看OSPF 邻居状态信息。 52-53、【答案】（52）B （53）A 【解析】掌握 OSPF几个重要命令： display ospf cumulative 查看 OSPF统计信息 display ospf spf-statistics 查看 OSPF进程下路由计算的统计信息 display ospf interface 查看 OSPF的接口信息 display ospf peer 查看 OSPF的邻居信息 display ospf Isdb 查看 OSPF的 Isdb display ospf routing 查看 OSPF的路由信息 display ospf error 查看 OSPF错误信息 reset ospf process 重启 OSPF进程 54、以下关于 IPv6地址的说法中，错误的是(54) 。 54、【答案】B 【解析】::只能使用1 次。 summer孇X Q èDe 、在 IPv6 中，(55)首部是每个中间路由器都需要处理的。 55、【答案】A 【解析】顾名思义。 56、在 GPON中，上行链路采用(56)的方式传输数据。 DMA 56、【答案】A 【解析】PON 网络上行为 TDMA，下行为广播。 57、在 PON 中，上行传输波长为 (57)nm。 57、【答案】B 【解析】PON 上行波形为 1310nm，下行波长为 1490nm。 58、某居民小区采用 FTTB+HGW网络组网，通常情况下，网络中的(58)部署在汇聚机 房。 58、【答案】C 【解析】FTTB 是光纤到建筑，即 PON 网络，核心设备是 OLT 和ONU，其中 OLT 部署在 机房。 59、以下关于光功率计的功能的说法中，错误的是(59)。 59、【答案】D 【解析】OTDR才能在一端测得损耗。 60-61、8 块300G的硬盘做 RAID5 后的容量是(60)，RAID5 最多可以损坏(61) 块硬盘 而不丢失数据。 60-61、【答案】（60）B （61）B 【解析】RAID5 空间利用率是 N-1，最多可以损耗1 块硬盘，数据不丢失。 62、在无线网络中，通过射频资源管理可以配置的任务不包括(62)。 62、【答案】D summer孇X Q èDe 【解析】 • 射频优调：比如自动调整信道或发射功率。 • 智能漫游：在 WLAN 网络中会存在粘性终端，通过主动引导的方式，使终端漫游到 信号更强的 AP。 • 频谱导航：由于物理特性，双频设备的信号，2.4G的信号强于 5G，即使速率比 5G 的慢，所以大多数的移动设备优先连接 2.4G。双频设备打开频谱导航后，将其均 衡地连接至该设备的不同射频上。 • 终端定位需要根据多个 AP 信号差，或时间差进行计算。 63、在无线网络中，天线最基本的属性不包括(63)。 63、【答案】B 【解析】天线有 3 个最基本的属性：方向性、极化、增益。 64-65、下列路由表的概要信息中，迭代路由是(64)，不同的静态路由有(65)条。 <HUAWEI> display ip routing table Route Flags: R-relay, D-download to fib ----------------------------------------------------------------- Routing Tables: Public Destinations : 6 Routes: 7 Destination/Mask Proto Pre Cost Flags NextHop Interface.', 2, '2021年综合知识', '2021,综合知识', 2021);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '0.1/32 Direct 0 0 D 127.0.0.1 InLoopBack0 64-65、【答案】（64）B （65）C summer孇X Q èDe 【', "["[['A. 10.10.0.0/24", "B. 10.2.2.2/32", "C. 127.0.0.0/8", "D. 10.1.1.1/32']]"]", '', '】Flag 带 R 的是迭代路由，迭代路由不论迭代出多少出接口和下一跳，仅统计 为一条路由。 （66）下列命令片段用于配置(66） <HUAWEI> system-view [~HUAWEI] interface 10ge1/0/1 [~HUAWEI-10GE1/0/1] loopback-detect enable [*HUAWEI-10GE1/0/1] commit 66、【答案】A 【解析】顾名思义，关键字 loopback-detect。 67、某主机可以 ping 通本机地址，而无法 ping通网关地址，网络配置如下图所示， 造成该故障的原因可能是(67) 。 67、【答案】B 【解析】缺图。 68-69、某分公司财务 PC 通过专网与总部财务系统连接，拓扑如下图所示。某天，财 务 PC 访问总部财务系统速度缓慢、时断时好，网络管理员在财务 PC 端ping总部财务 系统，发现有网络丢包，在光电转换器1 处 ping 总部财务系统网络丢包症状同上，在 专网接入终端处 ping 总部财务系统，网络延时正常无丢包，光纤1 两端测得光衰为- 28dBm，光电转换器1 和 2 指示灯绿色闪烁。初步判断该故障原因可能是(68)，可采用 (69)措施较为合理。 （69）A.更换财务 PC 终端网卡 68-69、【答案】（68）C （69）C summer孇X Q èDe 【解析】光纤光衰通常是指光纤每单位长度上的衰减值，单位为 dB/km。光衰理想的 范围：-20dBm 至 -25dBm。绿灯闪烁表示光电转换器没有问题。 70、以下关于项目风险管理的说法中，不正确的是(70) 。 70、【答案】A 【解析】风险无法完全避免。 71-75、Data security is the practice of protecting digital information from (71) access, corruption,or theft throughout its entire lifecycle. It is a concept that encompasses every aspect of information security from the (72) se curity of hardware and storage devices to administrative and access controls,as well as the logical security of software applications. It also in cludes organizational (73) and procedures.Data security involves deploying tools and technologies that enhance the organization\''s Visibility into where its critical data resides and how itis used. These tools and te chnologies should (74) the growing challenges inherent in securing today\''s complex distributed,hybrid,and/or multicloud computing environments.Ideally,these tools should be ableto apply protections like (75) ,data masking,and redaction of sensitive files, and should automate reporting to streamline audits and adhering to regulatory requirements. uthorized C .normal D. frequent ical C .network D. Information .policies D. structures .ignore D. pose ncryption C .decryption 71-75【答案】（71）A （72）B （73）C （74）A （75）B summer孇X Q èDe', 2, '2021年综合知识', '2021,综合知识', 2021);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '并发性是指若干串件在（3)发生。', "["[['A. 同一时刻", "B. 同一时间间隔内", "C. 不同时间间隔内", "D. 不同时刻']]"]", '', '', 2, '2023年综合知识', '2023,综合知识', 2023);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '使用海明码进行纠错， 7位码片（x心X X,iX心X )， 其中4位数据位， 3位校验位， 其监督关系式为 。 C =XX X心 C1=X 沈XX7 C产沈XsXX 如果收到的码字为1000101， 则纠错后的码字是(4)。 X心X心X凶，那么 。 C= X 1 X 3 XsX 1 = 1+ 1+ 0+1= 1 c 1 = X心X 6 X 7 = 0+1+ 0+1= O C产X 4 X心X 7 = 0+0+0+1= 1 此处按偶校验， 则CCC。 =101，那么转换成10进制数就是5，证明第5位出错，所以原码字就为1010101。', "["[['A. 1000001", "B. 1001101", "C. 1010101", "D. 1000101']]"]", '', '', 2, '2023年综合知识', '2023,综合知识', 2023);
