INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '可用性是网络管理中的一项重要指标假定一个双链路并联系统，每条链路可用性均为0.9; 主机 业务的峰值时段占整个工作时间的 60%，一条链路只能处理总业务量的 80%，需要两条链路同时工作 方能处理全部请求，非峰值时段约占整个工作时间的 40%，只需一条链路工作即可处理全部业务。整 个系统的平均可用性为53) 。', "["[['A. 0.9431", "B. 0. 8962", "C. 0. 9684", "D. 0. 9861']]"]", '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
