INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '某网络中 PC1 无法访问域名为 www. aaa. cn 的网站，而其他主机访问正常，在 PCL 上执行 ping fiz 令时有如下所示的信息: C:>ping www. aaa. cn Pinging www. aaa. cn[202. 117. 112.36] with 32 bytes of data: Reply from 202.117. 112.36: Destination net unreachable. Reply from 202. 117. 112. 36:Destination net unreachable. Reply from 202. 117. 112. 36:Destination net unreachable. Reply from 202. 117. 112.36: Destination net unreachable. Ping statistics for 202.117. 112. 36: Packets: Sent=4, Received=4, Lost=0(0% loss), Approximate round trip tunes in milli-seconds: Minimum=Oms, Maximum=Oms, Average=0ms 造成该现象可能的原因是 〈53) 。', "["[['A. DNS 服务器故障", "B. PCL 上TCPVZIP 协议故障", "C. 遭受了 ACL 拦截", "D. PC1 上 Internet 属性参数设置错误']]"]", '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
