INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '57、某大学拟建设无线校园网，委托甲公司承建，甲公司的张工带队去进行需求调研， 获得的主 要信息有: 校园面积约 4km ，要求在室外绝大部分区域及主要建筑物内实现覆盖，人允许同时上网用户数量为 5000 以上，非本校师生不允许自由接入，主要业务类型为上网浏览、电子邮件、FTP、QQ 等，后端与现有 校园网相连。张工据此撰写了需求分析报告，提交了录辑网络设计方案，其核心内容包括: GO网络拓扑设计 QAM weit QEREATI Rit Heep AC AT TE @@应用功能配置方案设计 以下三个方案中符合学校要求，合理可行的是: 无线网络选型的方案采用 〈55) ; 室外供电的方案是 〈56) ; 无线网络安全接入的方案是 〈57) 。 (55) A. 基于 WLAN 的技术建设无线校园网 B. 基于固定 WiMAX 的技术建设无线校园网', "["[['C. 直接利用电信运营商的 3G 系统", "D. 暂组执行，等待移动 WiMAX 成熟并商用", "A. 采用太阳能供电", "B. 地下埋设专用供电电线']]"]", '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
