INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '以下关于EFS (Encrypting File System) 的描述中，错误的是 (45) 。 密文件，非对称密钥中的公钥用于加密对称密钥。EFS加密发生在文件系统层而不在应用层，因此，其 加密和解密过程对加密用户和应用程序是透明的。用户在使用加密文件时 感觉与普通文件一样。', "["[['A. EFSSNTFS文件系统集成，提供文件加密", "B. EFS使用对称密钥加密文件，使用非对称密铀的公钥而索共享密钥", "C. EFS文件加密是在文件系统层而非应用层", "D. 独立的非联网计算机不能使用EFS为文件加密']]"]", '', '', 2, '2022年综合知识', '2022,综合知识', 2022);
