INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '假设操作系统页面为4KB，系统采用二级页表结构管理虚拟地址空间，最有可能导致内存访问的时间开销显著增加的是 (18) 。', "["[['A. 一级页表被频繁访问，因此操作系统将其常驻在高速缓存中以减少访问延迟", "B. 页表条目包含的有效位被置为无效，并且导致了一次缺页异常']]"]", '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
