INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '基于流水线设计的RISC处理器中，假设存在以下五个流水线阶段: 取指、指令译码、执行指令、访问内存、写回，最有可能导致严重的流水线阻塞，从而显著降低处理器性能的情况是 (27) 。', "["[['A. 在访存阶段，处理器遇到了一条存储指令，但数据缓存 (Cache) 命中了所需的数据", "B. 在执行过程中，遇到了一条条件分支指令，并且分支预测发生了错误']]"]", '', '', 2, '2024年综合知识', '2024,综合知识', 2024);